mapper.select:
SELECT id, article_id, user_id, source_id, title, chunk_index, total_chunks, chunk_text, create_time
FROM chunk
WHERE id = #{id}

SELECT COUNT(*)
FROM chunk
WHERE article_id = #{articleId}

SELECT id, article_id, user_id, source_id, title, chunk_index, total_chunks, chunk_text, create_time,
       MATCH(title, chunk_text) AGAINST (#{searchText} IN NATURAL LANGUAGE MODE) AS keyword_score
FROM chunk
WHERE user_id = #{userId}

    AND source_id = #{sourceId}

AND MATCH(title, chunk_text) AGAINST (#{searchText} IN NATURAL LANGUAGE MODE)
ORDER BY keyword_score DESC,
         create_time DESC,
         chunk_index ASC
LIMIT #{limit}
